1	/* ============================================================
2	   Algora client — two independent tabs (Assessment / Interview),
3	   each its own conversation. Streams /api/chat over fetch (SSE),
4	   renders thinking, tool calls, execution output, markdown answers,
5	   tables and Mermaid diagrams. Voice dictation via audio.js.
6	   ============================================================ */
7	
8	"use strict";
9	
10	// One source of truth for id generation (UUID, with a tiny fallback for old engines).
11	function rawId() {
12	  return (crypto.randomUUID && crypto.randomUUID()) ||
13	    "s-" + Math.abs(Date.now() ^ ((performance.now() * 1000) | 0)).toString(36);
14	}
15	function newSessionId(mode) {
16	  return rawId() + ":" + mode;
17	}
18	const TOUCH = window.matchMedia("(pointer: coarse)").matches;
19	
20	// Optional access token (only used if the server sets ALGORA_TOKEN).
21	let authToken = localStorage.getItem("algora_token") || "";
22	function authHeaders() {
23	  return authToken ? { "X-Algora-Token": authToken } : {};
24	}
25	function promptToken() {
26	  const t = window.prompt("This server requires an access token (ALGORA_TOKEN):", "");
27	  if (t) { authToken = t.trim(); localStorage.setItem("algora_token", authToken); }
28	  return authToken;
29	}
30	
31	// Collapse absolute workspace paths in tool output to just the filename, so a
32	// traceback reads `File "sol.py"` instead of leaking /Users/<me>/.../workspace/<id>/sol.py.
33	function stripWorkspacePaths(s) {
34	  return String(s).replace(/\/(?:[^\s"'\n]+\/)?workspace\/[^/\s"'\n]+\//g, "");
35	}
36	
37	const $ = (id) => document.getElementById(id);
38	const panels = document.querySelector(".panels");
39	const input = $("input");
40	const form = $("composer");
41	const sendBtn = $("send-btn");
42	const fileInput = $("file-input");
43	const attachBtn = $("attach-btn");
44	const micBtn = $("mic-btn");
45	const attachmentsEl = $("attachments");
46	const statusDot = $("status-dot");
47	const modelSelect = $("model-select");
48	const thinkingToggle = $("thinking-toggle");
49	const resetBtn = $("reset-btn");
50	const dropOverlay = $("drop-overlay");
51	
52	const PLACEHOLDERS = {
53	  assessment: "Describe the problem, or paste a screenshot…",
54	  interview: "Paste or dictate the problem — get a full interview walkthrough…",
55	  lld: "Name an OOD problem (e.g. design a parking lot) — or dictate it…",
56	  hld: "Name a system to design (e.g. design a URL shortener) — or dictate it…",
57	  behavioral: "Ask a behavioral question, or say 'tell me about yourself' — voice or text…",
58	};
59	
60	// ---------- per-tab state ----------
61	function makeTab(mode) {
62	  const el = panels.querySelector(`.transcript[data-mode="${mode}"]`);
63	  return {
64	    mode,
65	    el,
66	    sessionId: newSessionId(mode),
67	    emptyHTML: el.innerHTML,
68	    attachments: [],
69	    streaming: false,
70	    turn: null,
71	  };
72	}
73	const tabs = {
74	  assessment: makeTab("assessment"),
75	  interview: makeTab("interview"),
76	  lld: makeTab("lld"),
77	  hld: makeTab("hld"),
78	  behavioral: makeTab("behavioral"),
79	};
80	let active = "assessment";
81	const cur = () => tabs[active];
82	
83	// ============================================================
84	//  Tab switching
85	// ============================================================
86	// Reflect the active tab's session id in the URL (?s=…) so each session is easy to
87	// identify and a reload restores it. Uses replaceState — no page navigation.
88	function setUrlSession(id) {
89	  try {
90	    const u = new URL(window.location.href);
91	    if (id) u.searchParams.set("s", id); else u.searchParams.delete("s");
92	    history.replaceState(null, "", u);
93	  } catch (_) { /* non-fatal */ }
94	}
95	
96	// ── LP Coach embed ──────────────────────────────────────────────
97	// The LP Coach tab is a special case: it embeds an iframe to the
98	// skills-study-guide-ui project running on localhost:5173.
99	// It bypasses the session/streaming system entirely.
100	const lpPanel = $("lp-panel");
101	const lpIframe = $("lp-iframe");
102	const lpOffline = $("lp-offline");
103	const lpTab = $("lp-tab");
104	let lpActive = false;
105	
106	function lpCoachUrl() {
107	  // Use the same host that served Algora so the URL works on MacBook (0.0.0.0
108	  // or localhost) and on phone/tablet (LAN IP like 192.168.1.x) automatically.
109	  const host = window.location.hostname || "localhost";
110	  return `https://${host}:5173/google-interview-prep/chat`;
111	}
112	
113	function tryLoadLpIframe() {
114	  // Skip the fetch probe — it fails on self-signed certs even when the server
115	  // is up. Just set the src directly; if the server is down or the cert hasn't
116	  // been accepted yet, the browser shows its own "can't connect" page in the
117	  // iframe which is clear enough.
118	  const url = lpCoachUrl();
119	  if (lpIframe.src !== url) lpIframe.src = url;
120	  lpIframe.hidden = false;
121	  lpOffline.hidden = true;
122	}
123	
124	$("lp-reload").addEventListener("click", tryLoadLpIframe);
125	
126	function enterLpTab() {
127	  if (lpActive) return;
128	  lpActive = true;
129	  // Deactivate all regular tabs and hide their panels + composer
130	  for (const m in tabs) {
131	    tabs[m].el.hidden = true;
132	    tabs[m].el.classList.remove("is-active");
133	  }
134	  panels.hidden = true;
135	  form.hidden = true;
136	  lpPanel.hidden = false;
137	  document.querySelectorAll(".tab").forEach((b) => {
138	    b.classList.toggle("is-active", b === lpTab);
139	    b.setAttribute("aria-selected", b === lpTab ? "true" : "false");
140	  });
141	  tryLoadLpIframe();
142	}
143	
144	function exitLpTab() {
145	  if (!lpActive) return;
146	  lpActive = false;
147	  panels.hidden = false;
148	  form.hidden = false;
149	  lpPanel.hidden = true;
150	}
151	
152	lpTab.addEventListener("click", enterLpTab);
153	
154	function switchTab(mode) {
155	  if (!tabs[mode] || (mode === active && !lpActive)) return;
156	  exitLpTab();
157	  active = mode;
158	  setUrlSession(tabs[mode].sessionId);
159	  for (const m in tabs) {
160	    tabs[m].el.classList.toggle("is-active", m === mode);
161	    tabs[m].el.hidden = m !== mode;
162	  }
163	  document.querySelectorAll(".tab").forEach((b) => {
164	    const on = b.dataset.mode === mode;
165	    b.classList.toggle("is-active", on);
166	    b.setAttribute("aria-selected", on ? "true" : "false");
167	  });
168	  input.placeholder = PLACEHOLDERS[mode];
169	  renderAttachments();
170	  syncComposer();
171	}
172	document.querySelectorAll(".tab[data-mode]").forEach((b) =>
173	  b.addEventListener("click", () => switchTab(b.dataset.mode))
174	);
175	
176	function syncComposer() {
177	  const t = cur();
178	  sendBtn.disabled = t.streaming;
179	  if (t.streaming) {
180	    statusDot.className = "status-dot busy";
181	    statusDot.title = "working…";
182	  } else if (t.lastError) {
183	    statusDot.className = "status-dot err";
184	    statusDot.title = "last turn failed";
185	  } else {
186	    statusDot.className = "status-dot ok";
187	    statusDot.title = "ready";
188	  }
189	}
190	
191	// ============================================================
192	//  Transcript helpers (operate on an explicit tab)
193	// ============================================================
194	function clearEmpty(tab) {
195	  const es = tab.el.querySelector(".empty-state");
196	  if (es) es.remove();
197	}
198	function atBottom(tab) {
199	  return tab.el.scrollHeight - tab.el.scrollTop - tab.el.clientHeight < 140;
200	}
201	function scrollDown(tab, force) {
202	  if (force || atBottom(tab)) tab.el.scrollTop = tab.el.scrollHeight;
203	}
204	
205	function addUserMessage(tab, text, imgs) {
206	  clearEmpty(tab);
207	  const el = document.createElement("div");
208	  el.className = "msg user";
209	  let html = "";
210	  if (imgs && imgs.length) {
211	    html += `<div class="user-images">` +
212	      imgs.map((a) => `<img src="${a.dataUrl}" alt="attached image" />`).join("") + `</div>`;
213	  }
214	  if (text) html += `<div class="user-text"></div>`;
215	  el.innerHTML = html;
216	  if (text) el.querySelector(".user-text").textContent = text;
217	  tab.el.appendChild(el);
218	  scrollDown(tab, true);
219	}
220	
221	function startAssistantTurn(tab) {
222	  clearEmpty(tab);
223	  const el = document.createElement("div");
224	  el.className = "msg assistant";
225	  el.innerHTML =
226	    `<div class="assistant-label"><span class="al-name">Algora</span>` +
227	    `<button class="full-code-btn" type="button" title="View the complete code, file by file" hidden>📂 full code</button>` +
228	    `</div><div class="assistant-body"></div><div class="quick-actions" hidden></div>`;
229	  tab.el.appendChild(el);
230	  tab.turn = {
231	    msgEl: el,
232	    body: el.querySelector(".assistant-body"),
233	    thinkEl: null, thinkRaw: "",
234	    textEl: null, textRaw: "",
235	    toolCards: {},
236	    files: [],   // {path, content} from write_file calls — powers the "full code" modal
237	    raf: 0,
238	  };
239	  scrollDown(tab, true);
240	}
241	
242	function ensureThink(tab) {
243	  const turn = tab.turn;
244	  if (turn.thinkEl) return;
245	  const block = document.createElement("div");
246	  block.className = "think-block";
247	  block.innerHTML =
248	    `<div class="think-head"><span>🧠 Reasoning</span><span class="caret">▾</span></div>` +
249	    `<div class="think-body"></div>`;
250	  turn.body.appendChild(block);
251	  turn.thinkEl = block.querySelector(".think-body");
252	  turn.thinkRaw = "";
253	}
254	
255	function ensureText(tab) {
256	  const turn = tab.turn;
257	  if (turn.textEl) return;
258	  const p = document.createElement("div");
259	  p.className = "prose cursor";
260	  turn.body.appendChild(p);
261	  turn.textEl = p;
262	  turn.textRaw = "";
263	}
264	
265	function scheduleRender(tab) {
266	  const turn = tab.turn;
267	  if (turn.raf) return;
268	  turn.raf = requestAnimationFrame(() => {
269	    turn.raf = 0;
270	    if (turn.textEl) turn.textEl.innerHTML = renderMarkdown(turn.textRaw);
271	    scrollDown(tab);
272	  });
273	}
274	
275	// Flush the current streaming text block to its FINAL rendered state, then close it.
276	// Critical: a pending requestAnimationFrame render is guarded by `turn.textEl`, so if we
277	// null textEl (to start a tool card / next step) without flushing first, that pending
278	// frame fires, sees textEl === null, and silently DROPS the last streamed chunk — e.g.
279	// Sections 3-5 of the opener vanishing the moment the first tool card appears. Reload looks
280	// fine because the saved transcript renders in one pass. Always finalize before moving on.
281	function finalizeText(turn) {
282	  if (!turn) return;
283	  if (turn.raf) { cancelAnimationFrame(turn.raf); turn.raf = 0; }
284	  if (turn.textEl) {
285	    turn.textEl.innerHTML = renderMarkdown(turn.textRaw);
286	    turn.textEl.classList.remove("cursor");
287	    if (typeof renderMermaidIn === "function") renderMermaidIn(turn.textEl);
288	  }
289	  turn.textEl = null;
290	  turn.thinkEl = null;
291	}
292	
293	// ============================================================
294	//  Quick-action buttons — mode-specific follow-up prompts shown
295	//  below each completed assistant turn so one click fires the
296	//  most common next question without any typing.
297	// ============================================================
298	const QUICK_ACTIONS = {
299	  interview: [
300	    { label: "🔍 Brute Force",          prompt: "Walk me through the brute force approach step by step — narrate it exactly as I'd explain it out loud to an interviewer. Show the code too." },
301	    { label: "⚡ Optimal Deep Dive",    prompt: "Go line by line through the optimal solution. For each key step, tell me exactly what to say to the interviewer." },
302	    { label: "📖 Explain the Code",     prompt: "Explain the optimal code to me properly so I actually understand it, in simple Hinglish. Break it into a few logical parts; for each part show that piece of the code, then explain in plain words WHAT it does and WHY — like teaching a friend. Use small concrete examples and tiny diagrams where they help. This is for my own learning, not for narrating to an interviewer. At the end, give the whole thing in one Hinglish line, and invite me to ask about any single line or loop I'm stuck on." },
303	    { label: "💡 Core Intuition",       prompt: "What is the single key insight that makes the optimal solution work? Explain the 'aha' moment I should be able to articulate clearly." },
304	    { label: "🧪 Dry Run",              prompt: "Trace through the optimal solution on the problem's example — show exactly what's in each variable/data-structure at every step, like I'd draw on a whiteboard." },
305	    { label: "❓ Interviewer Follow-ups", prompt: "What are the 3 most likely follow-up questions an interviewer would ask after I present this solution? Give me each question and an ideal concise answer." },
306	    { label: "🎯 Quiz Me",              prompt: "Don't explain anything — quiz me instead. Ask me one targeted question to test my understanding of this solution, and wait for my answer before revealing anything." },
307	    { label: "📐 Edge Cases",           prompt: "What are the critical edge cases I must identify and handle? For each one, show what the solution does and what I should say to the interviewer." },
308	  ],
309	  assessment: [
310	    { label: "🧪 More Tests",           prompt: "Run 5 more adversarial test cases — especially edge cases the sample didn't cover. Verify the solution handles them all." },
311	    { label: "⚡ Optimize Further",     prompt: "Is there a way to optimize this solution further in time or space? If so, implement and verify the optimized version." },
312	    { label: "🔄 Alternative Approach", prompt: "Show me a completely different algorithmic approach to this problem. Compare both on time, space, and code simplicity." },
313	    { label: "🔍 Explain Logic",        prompt: "Explain the logic of this solution in plain English — what is the algorithm actually doing conceptually, step by step?" },
314	  ],
315	  lld: [
316	    { label: "🧩 Design Patterns",      prompt: "Which design patterns best strengthen this design and why? Show how to refactor one key class to apply one of them." },
317	    { label: "📊 Sequence Diagram",     prompt: "Generate a more detailed sequence diagram showing a complete end-to-end interaction flow through all layers." },
318	    { label: "🔒 Error Handling",       prompt: "Add comprehensive error handling and input validation to the existing code — show exactly what changes and why each matters." },
319	    { label: "🧪 Unit Tests",           prompt: "Write a thorough unit test suite for the core classes in this design." },
320	  ],
321	  hld: [
322	    { label: "📈 Scale 10x",            prompt: "Walk through what happens when this system gets 10x the expected load. What is the first bottleneck and exactly how would you fix it?" },
323	    { label: "🔒 Security",             prompt: "What are the top 3 security threats to this design and how would you mitigate each one concretely?" },
324	    { label: "💾 DB Deep Dive",         prompt: "Go deeper on the database layer — design the schema, key indexes, and explain the partitioning or sharding strategy with tradeoffs." },
325	    { label: "🔄 Failure Modes",        prompt: "Walk through the 3 most likely failure scenarios. What fails, what is the user impact, and how does the system detect and recover?" },
326	  ],
327	  behavioral: [
328	    { label: "💪 Strengthen It",        prompt: "Make this answer stronger — sharper numbers, clearer impact statement, tighter STAR structure. Show me the improved version." },
329	    { label: "🎯 LP Mapping",           prompt: "Which Amazon Leadership Principle is the strongest fit for this story? Rewrite the answer to make that connection explicit and compelling." },
330	    { label: "❓ Hard Follow-ups",      prompt: "What are the 3 hardest follow-up questions an interviewer could ask about this story? Give me an ideal response for each." },
331	    { label: "🔄 Different Angle",      prompt: "Reframe this same story to answer a different behavioral question type — pick the best alternative question it could answer and give the full answer." },
332	  ],
333	};
334	
335	function showQuickActions(tab) {
336	  const turn = tab.turn;
337	  if (!turn || !turn.msgEl) return;
338	  const qa = turn.msgEl.querySelector(".quick-actions");
339	  if (!qa) return;
340	  const actions = QUICK_ACTIONS[tab.mode] || [];
341	  if (!actions.length) return;
342	  qa.innerHTML = actions
343	    .map((a) => `<button class="quick-action-btn" data-prompt="${a.prompt.replace(/"/g, "&quot;")}">${a.label}</button>`)
344	    .join("");
345	  qa.hidden = false;
346	}
347	
348	const TOOL_META = {
349	  write_file: { cls: "write", icon: "✎", title: "write_file" },
350	  read_file: { cls: "read", icon: "▤", title: "read_file" },
351	  list_files: { cls: "read", icon: "≡", title: "list_files" },
352	  run_python: { cls: "run", icon: "▶", title: "run_python" },
353	  run_command: { cls: "run", icon: "$", title: "run_command" },
354	};
355	function targetForTool(name, inp) {
356	  if (!inp) return "";
357	  if (name === "write_file" || name === "read_file" || name === "run_python") return inp.path || "";
358	  if (name === "run_command") return inp.command || "";
359	  return "";
360	}
361	
362	function addToolCall(tab, ev) {
363	  const turn = tab.turn;
364	  finalizeText(turn);
365	
366	  const meta = TOOL_META[ev.name] || { cls: "read", icon: "•", title: ev.name };
367	  const card = document.createElement("div");
368	  card.className = "tool-card";
369	  const target = targetForTool(ev.name, ev.input);
370	
371	  let detail = "";
372	  if (ev.name === "write_file" && ev.input && ev.input.content != null) {
373	    const lang = (target.split(".").pop() || "").toLowerCase();
374	    detail = `<div class="tool-body">${renderCodeBlock(lang, String(ev.input.content))}</div>`;
375	    // Capture this file for the "full code" modal (dedup by path, last write wins — a
376	    // rewrite after a failed run is the corrected version).
377	    if (target) {
378	      const files = turn.files || (turn.files = []);
379	      const existing = files.find((f) => f.path === target);
380	      if (existing) existing.content = String(ev.input.content);
381	      else files.push({ path: target, content: String(ev.input.content) });
382	    }
383	  } else if (ev.name === "run_command") {
384	    detail = `<div class="tool-body"><pre>$ ${escapeHtml(target)}</pre></div>`;
385	  } else if (ev.name === "run_python" && ev.input && ev.input.stdin) {
386	    detail = `<div class="tool-body"><div class="io-label">stdin</div><pre>${escapeHtml(String(ev.input.stdin))}</pre></div>`;
387	  }
388	
389	  card.innerHTML =
390	    `<div class="tool-head">` +
391	    `<span class="tool-icon ${meta.cls}">${meta.icon}</span>` +
392	    `<span class="tool-title">${escapeHtml(meta.title)}</span>` +
393	    `<span class="tool-target">${escapeHtml(target)}</span>` +
394	    `<span class="tool-badge pending">running…</span>` +
395	    `</div>${detail}`;
396	  turn.body.appendChild(card);
397	  turn.toolCards[ev.id] = card;
398	  scrollDown(tab);
399	}
400	
401	function addWebSearch(tab, query) {
402	  const turn = tab.turn;
403	  finalizeText(turn);
404	  const el = document.createElement("div");
405	  el.className = "web-search-card";
406	  el.innerHTML = `<span class="ws-icon">🔎</span><span class="ws-text"></span>`;
407	  el.querySelector(".ws-text").textContent = query
408	    ? "Searched the web: " + query
409	    : "Searched the web…";
410	  turn.body.appendChild(el);
411	  scrollDown(tab);
412	}
413	
414	function addToolResult(tab, ev) {
415	  const card = tab.turn.toolCards[ev.id];
416	  if (!card) return;
417	  const badge = card.querySelector(".tool-badge");
418	  badge.classList.remove("pending");
419	  badge.classList.add(ev.is_error ? "err" : "ok");
420	  badge.textContent = ev.is_error ? "error" : "done";
421	
422	  const isRun = ev.name === "run_python" || ev.name === "run_command";
423	  const showOutput = isRun || ev.is_error || ev.name === "read_file" || ev.name === "list_files";
424	  if (showOutput) {
425	    let body = card.querySelector(".tool-body");
426	    if (!body) { body = document.createElement("div"); body.className = "tool-body"; card.appendChild(body); }
427	    const pre = document.createElement("pre");
428	    if (ev.is_error || /stderr ---\n(?!\(empty\))/.test(ev.output)) pre.className = "stderr";
429	    pre.textContent = stripWorkspacePaths(ev.output);
430	    body.appendChild(pre);
431	    // Only auto-expand FAILURES. A successful run shows its green "done" badge as proof;
432	    // its raw stdout is not what the candidate reads aloud, so keep it collapsed (one tap
433	    // to open). This removes the wall-of-output between the problem and the talking points.
434	    if (ev.is_error) card.classList.add("open");
435	  }
436	  scrollDown(tab);
437	}
438	
439	function showNotice(tab, msg) {
440	  if (!tab.turn) startAssistantTurn(tab);
441	  const turn = tab.turn;
442	  finalizeText(turn);
443	  const el = document.createElement("div");
444	  el.className = "notice-line";
445	  el.textContent = "ⓘ " + msg;
446	  turn.body.appendChild(el);
447	  scrollDown(tab);
448	}
449	
450	function showError(tab, msg) {
451	  tab.lastError = true;
452	  if (!tab.turn) startAssistantTurn(tab);
453	  const turn = tab.turn;
454	  finalizeText(turn);
455	  const el = document.createElement("div");
456	  el.className = "tool-card open error-card";
457	  el.innerHTML =
458	    `<div class="tool-head"><span class="tool-icon err-icon">!</span>` +
459	    `<span class="tool-title err-title">error</span></div>` +
460	    `<div class="tool-body"><pre class="stderr"></pre></div>`;
461	  el.querySelector("pre").textContent = msg;
462	  turn.body.appendChild(el);
463	  scrollDown(tab, true);
464	}
465	
466	function showUsage(tab, u) {
467	  if (!u || u.input_tokens == null) return;
468	  const parts = [`${u.input_tokens} in`, `${u.output_tokens} out`];
469	  if (u.cache_read_input_tokens) parts.push(`${u.cache_read_input_tokens} cached`);
470	  const tag = document.createElement("div");
471	  tag.className = "usage-line";
472	  tag.textContent = "↳ " + parts.join(" · ");
473	  tab.turn.body.appendChild(tag);
474	}
475	
476	function handleEvent(tab, ev) {
477	  switch (ev.type) {
478	    case "step_start":
479	      finalizeText(tab.turn);
480	      break;
481	    case "thinking_delta":
482	      ensureThink(tab);
483	      tab.turn.thinkRaw += ev.text;
484	      tab.turn.thinkEl.textContent = tab.turn.thinkRaw;
485	      scrollDown(tab);
486	      break;
487	    case "text_delta":
488	      ensureText(tab);
489	      tab.turn.textRaw += ev.text;
490	      scheduleRender(tab);
491	      break;
492	    case "web_search":
493	      addWebSearch(tab, ev.query);
494	      break;
495	    case "tool_call":
496	      addToolCall(tab, ev);
497	      break;
498	    case "tool_result":
499	      addToolResult(tab, ev);
500	      break;
501	    case "turn_done":
502	      // finalizeText owns the one true "flush streaming text" path (cancel pending rAF,
503	      // final render, drop cursor, draw mermaid) — reuse it instead of a second copy that
504	      // could drift out of sync. The body-level mermaid pass catches diagrams in earlier
505	      // text blocks too.
506	      finalizeText(tab.turn);
507	      renderMermaidIn(tab.turn.body);
