526	async function send() {
527	  const tab = cur();
528	  const text = input.value.trim();
529	  if ((!text && tab.attachments.length === 0) || tab.streaming) return;
530	
531	  tab.lastError = false;
532	  tab.passiveSession = null;  // this device is now the AUTHOR — stop live-sync polling/appending
533	  setUrlSession(tab.sessionId);  // this session is now running — show its id in the URL
534	  const imgs = tab.attachments.slice();
535	  addUserMessage(tab, text, imgs);
536	
537	  input.value = "";
538	  autosize();
539	  if (mic) mic.stop();  // Stop dictation so old text doesn't reappear on next dictation
540	  const payloadImages = imgs.map((a) => ({ media_type: a.media_type, data: a.data }));
541	  tab.attachments = [];
542	  renderAttachments();
543	
544	  setStreaming(tab, true);
545	  startAssistantTurn(tab);
546	
547	  const payload = {
548	    session_id: tab.sessionId,
549	    message: text,
550	    images: payloadImages,
551	    model: modelSelect.value,
552	    mode: tab.mode,
553	    thinking: thinkingToggle.classList.contains("is-on") ? undefined : 0,
554	  };
555	
556	  try {
557	    const resp = await fetch("/api/chat", {
558	      method: "POST",
559	      headers: { "Content-Type": "application/json", ...authHeaders() },
560	      body: JSON.stringify(payload),
561	    });
562	    if (resp.status === 401) {
563	      authToken = ""; localStorage.removeItem("algora_token"); promptToken();
564	      throw new Error("Unauthorized — enter the access token and try again.");
565	    }
566	    if (!resp.ok || !resp.body) {
567	      const t = await resp.text().catch(() => "");
568	      throw new Error(`HTTP ${resp.status} ${t}`);
569	    }
570	    const reader = resp.body.getReader();
571	    const decoder = new TextDecoder();
572	    let buffer = "";
573	    while (true) {
574	      const { value, done } = await reader.read();
575	      if (done) break;
576	      buffer += decoder.decode(value, { stream: true });
577	      let idx;
578	      while ((idx = buffer.indexOf("\n\n")) >= 0) {
579	        const chunk = buffer.slice(0, idx);
580	        buffer = buffer.slice(idx + 2);
581	        const m = chunk.match(/^data:\s?([\s\S]*)$/);
582	        if (!m) continue;
583	        try { handleEvent(tab, JSON.parse(m[1])); }
584	        catch (err) { console.error("bad event", m[1], err); }
585	      }
586	    }
587	  } catch (err) {
588	    tab.pendingRecovery = true;  // attempt server-side recovery on next foreground
589	    // Show a soft "resuming" notice instead of a hard error — the server keeps
590	    // generating even after iOS suspends the browser; we'll auto-load on return.
591	    if (!tab.turn) startAssistantTurn(tab);
592	    finalizeText(tab.turn);
593	    const notice = document.createElement("div");
594	    notice.className = "notice-line bg-resume-notice";
595	    notice.textContent = "⏳ Generating in background — come back to see your answer.";
596	    tab.turn.body.appendChild(notice);
597	    scrollDown(tab);
598	  } finally {
599	    setStreaming(tab, false); // syncComposer reflects the error state for the active tab
600	  }
601	}
