615	function fileToAttachment(file) {
616	  return new Promise((resolve) => {
617	    if (!file.type.startsWith("image/")) return resolve(null);
618	    const r = new FileReader();
619	    r.onload = () => {
620	      const dataUrl = r.result;
621	      resolve({ media_type: file.type, data: dataUrl.slice(dataUrl.indexOf(",") + 1), dataUrl });
622	    };
623	    r.onerror = () => resolve(null);
624	    r.readAsDataURL(file);
625	  });
626	}
