1005	async function restoreConversation(id, mode) {
1006	  let data;
1007	  try {
1008	    const r = await fetch(`/api/conversations/${encodeURIComponent(id)}`, { headers: authHeaders() });
1009	    if (!r.ok) throw new Error("not found");
1010	    data = await r.json();
1011	  } catch { return; }
1012	  mode = mode || data.mode || active;
1013	  if (mode !== active) switchTab(mode);
1014	  const t = tabs[mode];
1015	  if (t.streaming) { closeHistory(); return; }
1016	  t.el.innerHTML = "";
1017	  t.turn = null; t.lastError = false; t.attachments = [];
1018	  t.sessionId = id; // follow-ups continue THIS conversation
1019	  setUrlSession(id);
1020	  const tr = data.transcript || [];
1021	  let lastRole = null;
1022	  for (const it of tr) {
1023	    if (it.role === "user") {
1024	      const txt = (it.images ? `📎 ${it.images} image(s)\n` : "") + (it.text || "");
1025	      addUserMessage(t, txt, []);
1026	    } else {
1027	      renderSavedAssistant(t, it);
1028	    }
1029	    lastRole = it.role;
1030	  }
