1088	// Live-sync a conversation this device is PASSIVELY viewing (restored from history): if
1089	// another device adds a turn, the server transcript grows and we append the new turns here.
1090	async function liveSyncTick() {
1091	  const t = cur();
1092	  if (!t || t.streaming || !t.passiveSession || document.hidden) return;
1093	  const id = t.passiveSession;
1094	  try {
1095	    const r = await fetch(`/api/conversations/${encodeURIComponent(id)}`, { headers: authHeaders() });
1096	    if (!r.ok) return;
1097	    const data = await r.json();
1098	    // bail if anything changed while we awaited (tab switch / send / restore)
1099	    if (t !== cur() || t.passiveSession !== id || t.streaming) return;
1100	    const tr = data.transcript || [];
1101	    if (tr.length <= (t.renderedCount || 0)) return;
1102	    const wasBottom = atBottom(t);
1103	    let syncLastRole = null;
1104	    for (let k = t.renderedCount || 0; k < tr.length; k++) {
1105	      const it = tr[k];
1106	      if (it.role === "user") {
1107	        addUserMessage(t, (it.images ? `📎 ${it.images} image(s)\n` : "") + (it.text || ""), []);
1108	      } else {
1109	        renderSavedAssistant(t, it);
1110	      }
1111	      syncLastRole = it.role;
1112	    }
1113	    t.renderedCount = tr.length;
1114	    if (syncLastRole === "assistant") showQuickActions(t);
1115	    if (wasBottom) t.el.scrollTop = t.el.scrollHeight;
1116	  } catch { /* transient — try again next tick */ }
1117	}
