1119	// When a stream fails because iOS backgrounded the app (fetch connection drops while
1120	// suspended), the server's agent keeps running and saves the completed response via
1121	// _persist_turn(). On foreground, we poll until the assistant turn appears, then
1122	// silently re-render the full conversation — no error card, seamless resume.
1123	async function tryRecoverInterruptedStream() {
1124	  const t = cur();
1125	  if (!t || !t.pendingRecovery || t.streaming) return;
1126	  t.pendingRecovery = false;
1127	  const id = t.sessionId;
1128	  if (!id) return;
1129	
1130	  // Poll up to ~60s (12 × 5s) — covers long behavioral / code answers.
1131	  for (let attempt = 0; attempt < 12; attempt++) {
1132	    await new Promise(r => setTimeout(r, attempt === 0 ? 1500 : 5000));
1133	    if (t !== cur() || t.streaming || !id) return;  // user navigated away or sent a new msg
1134	    try {
1135	      const r = await fetch(`/api/conversations/${encodeURIComponent(id)}`, { headers: authHeaders() });
1136	      if (!r.ok) continue;
1137	      const data = await r.json();
1138	      const tr = data.transcript || [];
1139	      if (!tr.length || tr[tr.length - 1].role !== "assistant") continue;
1140	      // Got the completed assistant turn — clear partial content and re-render cleanly.
1141	      t.el.innerHTML = "";
1142	      t.turn = null; t.lastError = false;
1143	      for (const it of tr) {
1144	        if (it.role === "user") {
1145	          addUserMessage(t, (it.images ? `📎 ${it.images} image(s)\n` : "") + (it.text || ""), []);
1146	        } else {
1147	          renderSavedAssistant(t, it);
1148	        }
1149	      }
1150	      showQuickActions(t);
1151	      t.el.scrollTop = t.el.scrollHeight;
1152	      return;  // done
1153	    } catch { /* transient — retry */ }
1154	  }
1155	  // All retries exhausted — show a real error so user knows to re-send.
1156	  if (!t.turn) startAssistantTurn(t);
1157	  const notice = t.el.querySelector(".bg-resume-notice");
1158	  if (notice) {
1159	    notice.className = "tool-card open error-card";
1160	    notice.innerHTML =
1161	      `<div class="tool-head"><span class="tool-icon err-icon">!</span>` +
1162	      `<span class="tool-title err-title">error</span></div>` +
1163	      `<div class="tool-body"><pre class="stderr">Response lost — please re-send your message.</pre></div>`;
1164	  }
1165	}
