348	  transition: transform var(--dur) var(--ease), border-color var(--dur) var(--ease), color var(--dur) var(--ease), background var(--dur) var(--ease);
349	  white-space: nowrap;
350	}
351	.quick-action-btn:hover {
352	  transform: translateY(-1px);
353	  border-color: var(--accent);
354	  color: var(--text);
355	  background: oklch(72% 0.16 45 / 0.07);
356	}
