358	
359	/* message rows */
360	.msg { animation: rise var(--dur) var(--ease); }
361	@keyframes rise { from { opacity: 0; transform: translateY(8px); } }
362	
363	.msg.user {
364	  align-self: flex-end;
365	  max-width: min(85%, 640px);
366	  background: linear-gradient(160deg, var(--accent-soft), oklch(72% 0.16 45 / 0.05));
