372	.msg.user .user-images { display: flex; flex-wrap: wrap; gap: 8px; margin-bottom: 8px; }
373	.msg.user .user-images img { max-width: 160px; max-height: 160px; border-radius: 8px; border: 1px solid var(--border-strong); }
374	.msg.user .user-text { white-space: pre-wrap; word-break: break-word; }
375	
376	.msg.assistant {
377	  align-self: stretch;
378	  max-width: 100%;
379	}
380	.assistant-label {
381	  display: flex; align-items: center; gap: 8px;
382	  font-size: 0.72rem; color: var(--text-faint);
383	  text-transform: uppercase; letter-spacing: 0.1em;
384	  margin-bottom: 8px;
385	}
386	.assistant-label::before {
387	  content: "";
388	  width: 16px; height: 16px; border-radius: 5px;
389	  background: linear-gradient(145deg, var(--accent), oklch(60% 0.16 30));
390	}
391	
392	/* ---------- Reasoning (thinking) ---------- */
393	.think-block {
394	  border: 1px solid oklch(74% 0.10 300 / 0.3);
395	  background: oklch(74% 0.10 300 / 0.06);
396	  border-radius: var(--radius-sm);
397	  margin: 0 0 12px;
398	  overflow: hidden;
399	}
400	.think-head {
401	  display: flex; align-items: center; gap: 8px;
402	  padding: 9px 13px;
403	  cursor: pointer;
404	  font-size: 0.78rem;
405	  font-weight: 600;
406	  color: var(--think);
407	  user-select: none;
408	}
409	.think-head .caret { transition: transform var(--dur) var(--ease); margin-left: auto; opacity: 0.6; }
410	.think-block.collapsed .caret { transform: rotate(-90deg); }
411	.think-body {
412	  padding: 0 13px 11px;
413	  font-size: 0.83rem;
414	  color: var(--text-dim);
415	  white-space: pre-wrap;
416	  word-break: break-word;
417	  font-family: var(--font-mono);
418	  line-height: 1.55;
419	  max-height: 320px;
420	  overflow-y: auto;
421	}
422	.think-block.collapsed .think-body { display: none; }
423	
424	/* ---------- Tool event cards ---------- */
425	.tool-card {
426	  border: 1px solid var(--border);
427	  border-radius: var(--radius-sm);
428	  background: var(--surface);
429	  margin: 0 0 12px;
430	  overflow: hidden;
431	  box-shadow: var(--shadow-lo);
432	}
433	.tool-head {
434	  display: flex; align-items: center; gap: 9px;
435	  padding: 9px 13px;
436	  font-family: var(--font-mono);
437	  font-size: 0.78rem;
438	  border-bottom: 1px solid transparent;
439	  cursor: pointer;
440	  user-select: none;
441	}
442	.tool-card.open .tool-head { border-bottom-color: var(--border); }
443	.tool-icon {
444	  width: 18px; height: 18px; flex: none;
445	  display: grid; place-items: center;
446	  border-radius: 5px;
447	  font-size: 0.7rem; font-weight: 700;
448	}
449	.tool-icon.write { background: var(--accent-soft); color: var(--accent-strong); }
450	.tool-icon.run { background: var(--run-soft); color: var(--run); }
451	.tool-icon.read { background: var(--surface-3); color: var(--text-dim); }
452	.tool-title { font-weight: 600; color: var(--text); }
453	.tool-target { color: var(--text-dim); overflow: hidden; text-overflow: ellipsis; white-space: nowrap; }
454	.tool-badge {
455	  margin-left: auto; flex: none;
456	  font-size: 0.68rem; font-weight: 700;
457	  padding: 2px 8px; border-radius: 999px;
458	  letter-spacing: 0.04em;
459	}
460	.tool-badge.ok { background: var(--run-soft); color: var(--run); }
461	.tool-badge.err { background: oklch(70% 0.19 25 / 0.15); color: var(--danger); }
462	.tool-badge.pending { background: var(--surface-3); color: var(--text-faint); }
463	.tool-body { display: none; }
464	.tool-card.open .tool-body { display: block; }
465	.tool-body pre {
466	  margin: 0;
467	  padding: 12px 14px;
468	  font-family: var(--font-mono);
469	  font-size: 0.78rem;
470	  line-height: 1.5;
471	  overflow-x: auto;
472	  white-space: pre;
473	  color: var(--text-dim);
474	}
475	.tool-body pre.stderr { color: oklch(78% 0.12 25); }
476	.io-label {
477	  font-family: var(--font-mono);
478	  font-size: 0.66rem; letter-spacing: 0.08em; text-transform: uppercase;
479	  color: var(--text-faint);
480	  padding: 8px 14px 0;
481	}
482	
483	/* ---------- Markdown / prose ---------- */
484	.prose { word-break: break-word; }
485	.prose p { margin: 0 0 0.85em; }
486	.prose h1, .prose h2, .prose h3 { line-height: 1.3; margin: 1.1em 0 0.5em; letter-spacing: -0.01em; }
487	.prose h1 { font-size: 1.3rem; }
488	/* h2 = the section landmark. Bigger + a top rule so a candidate thumb-scrolling on a
489	   phone can instantly see where the next section begins. */
490	.prose h2 {
491	  font-size: 1.32rem;
492	  font-weight: 720;
493	  margin-top: 1.7em;
494	  padding-top: 0.7em;
495	  border-top: 1px solid var(--border);
496	}
497	.prose h2:first-child { border-top: none; padding-top: 0; margin-top: 0.2em; }
498	.prose h3 { font-size: 1.03rem; color: var(--accent-strong); }
499	.prose ul, .prose ol { margin: 0 0 0.85em; padding-left: 1.4em; }
500	.prose li { margin: 0.2em 0; }
501	.prose strong { color: var(--text); font-weight: 680; }
502	.prose a { color: var(--accent-strong); }
503	.prose blockquote {
504	  border-left: 3px solid var(--accent); margin: 0 0 0.85em; padding: 0.2em 0 0.2em 1em;
505	  color: var(--text-dim);
506	}
507	/* Quiet inline code: a subtle mono tint, no border, no loud fill — so a paragraph
508	   full of variable names reads as prose, not a row of buttons. */
509	.prose code.inline {
510	  font-family: var(--font-mono);
511	  font-size: 0.88em;
512	  background: oklch(100% 0 0 / 0.05);
513	  padding: 0.5px 4px;
514	  border-radius: 4px;
515	  color: var(--text);
516	}
517	
518	.code-block {
519	  position: relative;
520	  background: oklch(12% 0.01 265);
521	  border: 1px solid var(--border);
522	  border-radius: var(--radius-sm);
523	  margin: 0 0 0.9em;
524	  overflow: hidden;
525	}
526	.code-block .code-bar {
527	  display: flex; align-items: center; justify-content: space-between;
528	  padding: 6px 10px 6px 12px;
529	  background: var(--surface);
530	  border-bottom: 1px solid var(--border);
531	}
532	.code-lang { font-family: var(--font-mono); font-size: 0.68rem; color: var(--text-faint); letter-spacing: 0.06em; text-transform: uppercase; }
533	.code-lang:empty { display: none; }  /* no "TEXT" chip on plain/ascii blocks */
534	.copy-btn {
535	  background: transparent; border: 1px solid var(--border); color: var(--text-dim);
536	  font-size: 0.68rem; font-weight: 600; padding: 3px 9px; border-radius: 6px; cursor: pointer;
537	  transition: color var(--dur) var(--ease), border-color var(--dur) var(--ease);
538	}
539	.copy-btn:hover { color: var(--text); border-color: var(--border-strong); }
540	.copy-btn.copied { color: var(--run); border-color: var(--run); }
541	.code-block pre {
542	  margin: 0; padding: 13px 14px; overflow-x: auto;
543	  font-family: var(--font-mono); font-size: 0.82rem; line-height: 1.55;
544	  color: oklch(90% 0.01 265);
545	}
546	/* tiny python-ish syntax tint */
547	.tok-kw { color: oklch(74% 0.13 300); }
548	.tok-str { color: oklch(80% 0.13 140); }
549	.tok-num { color: oklch(80% 0.12 60); }
550	.tok-com { color: var(--text-faint); font-style: italic; }
551	.tok-def { color: oklch(80% 0.12 230); }
552	
553	.cursor::after {
554	  content: "▍"; color: var(--accent); margin-left: 1px;
555	  animation: blink 1s steps(1) infinite;
556	}
557	@keyframes blink { 50% { opacity: 0; } }
558	
559	/* ---------- Attachments preview ---------- */
560	.attachments {
561	  display: flex; flex-wrap: wrap; gap: 8px;
562	  padding: 8px clamp(14px, 4vw, 26px) 0;
563	}
564	.attachment {
565	  position: relative; width: 56px; height: 56px; border-radius: 9px; overflow: hidden;
566	  border: 1px solid var(--border-strong);
567	}
568	.attachment img { width: 100%; height: 100%; object-fit: cover; }
569	.attachment button {
570	  position: absolute; top: 2px; right: 2px;
571	  width: 18px; height: 18px; border-radius: 50%; border: 0;
572	  background: oklch(0% 0 0 / 0.6); color: #fff; cursor: pointer; font-size: 0.7rem; line-height: 1;
573	  display: grid; place-items: center;
574	}
575	
576	/* ---------- Composer ---------- */
577	.composer {
578	  display: flex; align-items: flex-end; gap: 9px;
579	  padding: 12px clamp(14px, 4vw, 26px);
580	  padding-bottom: max(12px, env(safe-area-inset-bottom));
581	  border-top: 1px solid var(--border);
582	  background: oklch(16% 0.012 265 / 0.85);
583	  backdrop-filter: blur(14px);
584	}
585	.icon-btn, .send-btn {
586	  flex: none;
587	  width: 42px; height: 42px;
588	  border-radius: 11px;
589	  border: 1px solid var(--border);
590	  background: var(--surface-2);
591	  color: var(--text-dim);
592	  cursor: pointer;
593	  display: grid; place-items: center;
594	  transition: color var(--dur) var(--ease), border-color var(--dur) var(--ease), background var(--dur) var(--ease), transform var(--dur) var(--ease);
595	}
596	.icon-btn:hover { color: var(--text); border-color: var(--border-strong); }
597	.send-btn { background: var(--accent); color: oklch(18% 0.02 45); border-color: transparent; }
598	.send-btn:hover { background: var(--accent-strong); transform: translateY(-1px); }
599	.send-btn:disabled { opacity: 0.4; cursor: not-allowed; transform: none; }
600	
601	#input {
602	  flex: 1;
603	  resize: none;
604	  max-height: 180px;
605	  background: var(--surface);
606	  border: 1px solid var(--border);
607	  border-radius: 12px;
608	  color: var(--text);
609	  font-family: var(--font-sans);
610	  font-size: 1rem; /* >=16px prevents iOS zoom-on-focus */
611	  line-height: 1.45;
612	  padding: 10px 13px;
613	  outline: none;
614	  transition: border-color var(--dur) var(--ease);
615	}
616	#input:focus { border-color: var(--accent); }
617	#input::placeholder { color: var(--text-faint); }
618	
619	/* ---------- Drop overlay ---------- */
620	.drop-overlay {
621	  position: fixed; inset: 0; z-index: 50;
622	  background: oklch(15% 0.012 265 / 0.85);
623	  display: grid; place-items: center;
624	  backdrop-filter: blur(6px);
625	}
626	.drop-card {
627	  border: 2px dashed var(--accent);
628	  border-radius: var(--radius);
629	  padding: 40px 60px;
630	  font-size: 1.1rem; font-weight: 600; color: var(--accent-strong);
631	}
632	
633	/* ---------- Scrollbars ---------- */
634	.transcript::-webkit-scrollbar, .think-body::-webkit-scrollbar, .tool-body pre::-webkit-scrollbar, .code-block pre::-webkit-scrollbar { width: 9px; height: 9px; }
635	.transcript::-webkit-scrollbar-thumb, .think-body::-webkit-scrollbar-thumb, .tool-body pre::-webkit-scrollbar-thumb, .code-block pre::-webkit-scrollbar-thumb {
636	  background: var(--border-strong); border-radius: 10px; border: 2px solid transparent; background-clip: padding-box;
637	}
638	
639	/* ---------- Talking points (interview "what to say") ---------- */
640	.prose blockquote.talk {
641	  border-left: 3px solid var(--run);
642	  background: var(--run-soft);
643	  border-radius: 0 8px 8px 0;
644	  color: var(--text);
645	  font-style: normal;
646	  padding: 8px 12px 8px 14px;
647	}
648	
649	/* ---------- 🎙️ Script (the connected narration the candidate SPEAKS) ----------
650	   The single most important design-mode element. A clay-accent teleprompter block,
651	   deliberately distinct from the cyan-green 💬 say-lines so the eye finds it instantly. */
652	.prose .script-block {
653	  border: 1px solid oklch(72% 0.16 45 / 0.4);
654	  border-left: 3px solid var(--accent);
655	  background: oklch(72% 0.16 45 / 0.08);
656	  border-radius: 0 10px 10px 0;
657	  margin: 0 0 1em;
658	  padding: 9px 14px 11px;
659	}
660	.prose .script-head {
661	  font-size: 0.64rem; letter-spacing: 0.09em; text-transform: uppercase;
662	  color: var(--accent-strong); font-weight: 700; margin-bottom: 5px;
663	}
664	.prose .script-body { color: var(--text); line-height: 1.65; }
665	
666	/* ---------- Conversational beats (🤝 checkpoint / 🆘 stuck / 🧠 if-they-ask / ⚠️ trap) ----------
667	   A semantic colored left-border + faint tint each — readable signposts, not a sticker sheet. */
668	.prose blockquote.check, .prose blockquote.sos, .prose blockquote.ask, .prose blockquote.trap,
669	.prose blockquote.voice, .prose blockquote.hard, .prose blockquote.warn,
670	.prose blockquote.fork, .prose blockquote.prev, .prose blockquote.math,
671	.prose blockquote.ok, .prose blockquote.upgrade, .prose blockquote.tradeoff,
672	.prose blockquote.script {
673	  font-style: normal; border-radius: 0 8px 8px 0; padding: 8px 12px 8px 14px; color: var(--text);
674	}
675	.prose blockquote.check    { border-left: 3px solid var(--accent); background: var(--accent-soft); }
676	.prose blockquote.sos      { border-left: 3px solid var(--think); background: oklch(74% 0.10 300 / 0.10); }
677	.prose blockquote.ask      { border-left: 3px solid oklch(80% 0.13 80); background: oklch(80% 0.13 80 / 0.09); }
678	.prose blockquote.trap     { border-left: 3px solid var(--danger); background: oklch(70% 0.19 25 / 0.09); }
679	
680	/* 🗣️ Plain-words / "how to say it" explanation */
681	.prose blockquote.voice    { border-left: 3px solid oklch(70% 0.14 260); background: oklch(70% 0.14 260 / 0.08); }
682	/* ⚡ Why it's hard */
683	.prose blockquote.hard     { border-left: 3px solid oklch(78% 0.15 60); background: oklch(78% 0.15 60 / 0.07); }
684	/* 💥 What breaks without it */
685	.prose blockquote.warn     { border-left: 3px solid var(--danger); background: oklch(70% 0.19 25 / 0.06); color: var(--text-dim); }
686	/* ↔️ Design fork */
687	.prose blockquote.fork     { border-left: 3px solid oklch(72% 0.16 200); background: oklch(72% 0.16 200 / 0.07); }
688	/* ↩️ What previous tier got wrong */
689	.prose blockquote.prev     { border-left: 3px solid oklch(65% 0.14 280); background: oklch(65% 0.14 280 / 0.07); }
690	/* 🔢 Decision math */
691	.prose blockquote.math     { border-left: 3px solid oklch(80% 0.12 200); background: oklch(80% 0.12 200 / 0.06); font-family: var(--font-mono); font-size: 0.88em; }
692	/* ✅ Failure matrix / success */
693	.prose blockquote.ok       { border-left: 3px solid var(--run); background: oklch(78% 0.15 165 / 0.07); }
694	/* 🔁 What forces the upgrade */
695	.prose blockquote.upgrade  { border-left: 3px solid oklch(78% 0.13 50); background: oklch(78% 0.13 50 / 0.07); }
696	/* 🔀 Trade-off */
697	.prose blockquote.tradeoff { border-left: 3px solid var(--think); background: oklch(74% 0.10 300 / 0.07); }
698	/* 🎙️ Script (when emitted as a blockquote rather than the <aside> path) */
699	.prose blockquote.script   { border-left: 3px solid var(--accent); background: oklch(72% 0.16 45 / 0.07); font-style: italic; }
700	
701	/* "> - item" inside blockquotes — the design-fork bullets */
702	.prose .bq-li {
703	  display: list-item; list-style: disc;
704	  margin: 0.2em 0 0.2em 2.2em;
705	  color: var(--text-dim); font-size: 0.93rem;
706	  line-height: 1.55;
707	}
708	
709	/* ---------- Deep-dive tiers (Bad / Good / Great cards) ---------- */
710	.tier {
711	  border: 1px solid var(--border);
712	  border-left-width: 3px;
713	  border-radius: 11px;
714	  padding: 12px 15px 4px;
715	  margin: 0 0 12px;
716	}
717	.tier-head { display: flex; align-items: center; gap: 10px; margin-bottom: 9px; }
718	.tier-badge {
719	  flex: none;
720	  font-size: 0.6rem; font-weight: 800; letter-spacing: 0.12em; text-transform: uppercase;
721	  padding: 3px 10px; border-radius: 999px;
722	}
723	.tier-title { font-weight: 650; font-size: 0.95rem; color: var(--text); line-height: 1.35; }
724	.tier > p, .tier > ul, .tier > ol { margin-bottom: 0.55em; }
725	.tier .code-block, .tier .mermaid-block { margin-bottom: 0.7em; }
726	
727	.tier-bad { border-left-color: var(--danger); background: oklch(70% 0.19 25 / 0.055); }
728	.tier-bad .tier-badge { background: oklch(70% 0.19 25 / 0.2); color: oklch(82% 0.14 25); }
729	.tier-good { border-left-color: oklch(80% 0.13 80); background: oklch(80% 0.13 80 / 0.06); }
730	.tier-good .tier-badge { background: oklch(80% 0.13 80 / 0.2); color: oklch(86% 0.12 85); }
731	.tier-great { border-left-color: var(--run); background: oklch(78% 0.15 165 / 0.07); }
732	.tier-great .tier-badge { background: oklch(78% 0.15 165 / 0.2); color: var(--run); }
733	
734	/* Approach / Challenges / Trade-off labels inside a tier */
735	.dd-label {
736	  display: inline-block;
737	  font-size: 0.64rem; font-weight: 700; letter-spacing: 0.05em; text-transform: uppercase;
738	  color: var(--text-dim);
739	  background: var(--surface-2); border: 1px solid var(--border);
740	  padding: 1px 8px; border-radius: 6px; margin: 0 5px 0 0; vertical-align: 1px;
741	}
742	
743	/* ---------- Tables (DP tables / array states) ---------- */
744	.table-wrap { overflow-x: auto; margin: 0 0 0.9em; border-radius: var(--radius-sm); border: 1px solid var(--border); }
745	.prose table { border-collapse: collapse; width: 100%; font-size: 0.84rem; }
746	.prose th, .prose td {
747	  border: 1px solid var(--border);
748	  padding: 6px 10px;
749	  text-align: left;
750	}
751	/* Only headers stay on one line; data cells wrap so DP/state tables fit a phone
752	   column instead of forcing a sideways swipe mid-sentence. */
753	.prose th { white-space: nowrap; }
754	.prose thead th { background: var(--surface-2); color: var(--text); font-weight: 650; }
755	.prose tbody tr:nth-child(even) { background: oklch(22% 0.014 265 / 0.4); }
756	.prose td code.inline { background: transparent; border: none; padding: 0; }
757	
758	/* ---------- Mermaid diagrams ---------- */
759	.mermaid-block {
760	  position: relative;
761	  margin: 0 0 1em;
762	  padding: 14px;
763	  background: oklch(13% 0.01 265);
764	  border: 1px solid var(--border);
765	  border-radius: var(--radius-sm);
766	  overflow-x: auto;
767	  overflow-y: hidden;
768	  text-align: center;
769	  -webkit-overflow-scrolling: touch; /* momentum scroll on iOS */
770	}
771	.mermaid-block.rendered { background: oklch(15% 0.012 265); cursor: zoom-in; }
772	/* Persistent "tap to enlarge" hint so a wide/clipped diagram's tap-to-zoom is discoverable
773	   (especially on a phone, where a big cumulative HLD flowchart paints pre-clipped). */
774	.mermaid-block.rendered::after {
775	  content: "⤢ tap to enlarge";
776	  position: absolute; bottom: 6px; right: 8px;
777	  font-size: 0.6rem; color: var(--text-dim);
778	  background: oklch(0% 0 0 / 0.45); padding: 2px 8px; border-radius: 999px;
779	  pointer-events: none;
780	}
781	/* wide diagrams: anchor to the left (the part you read first) instead of mid-canvas */
782	.mermaid-block.mmd-wide { text-align: left; }
783	/* width:auto + max-width:none lets the SVG keep its natural size so the block
784	   scrolls horizontally instead of shrinking the diagram to fit the column. */
785	.mermaid-block svg { width: auto; max-width: none; height: auto; display: inline-block; }
786	/* Readable floor for label text regardless of any residual scaling. */
787	.mermaid-block svg .nodeLabel,
788	.mermaid-block svg .edgeLabel,
789	.mermaid-block svg .cluster-label,
790	.mermaid-block svg text { font-size: 15px; }
791	
792	/* Tap-to-zoom fullscreen overlay (laptop + iPhone) */
793	.mermaid-zoom {
