1	/* ============================================================
2	   Self-contained Markdown renderer (no external deps for text):
3	   - HTML-escaped output (XSS-safe for model/tool output)
4	   - fenced code blocks with copy button + light Python highlight
5	   - GFM tables (great for DP tables / array states)
6	   - Mermaid blocks -> rendered to SVG via the vendored mermaid lib,
7	     loaded lazily only when a diagram actually appears.
8	   Exposes globals: escapeHtml, renderMarkdown, renderMermaidIn.
9	   ============================================================ */
10	
11	"use strict";
12	
13	function escapeHtml(s) {
14	  // Escapes quotes too, so escaped text is safe inside quoted HTML attributes
15	  // (e.g. link href, data-* attrs) — not just in text nodes.
16	  return String(s)
17	    .replace(/&/g, "&amp;")
18	    .replace(/</g, "&lt;")
19	    .replace(/>/g, "&gt;")
20	    .replace(/"/g, "&quot;")
21	    .replace(/'/g, "&#39;");
22	}
23	
24	const PY_TOKENS =
25	  /(#[^\n]*)|("""[\s\S]*?"""|'''[\s\S]*?'''|"(?:\\.|[^"\\])*"|'(?:\\.|[^'\\])*')|\b(def|class|return|if|elif|else|for|while|in|not|and|or|import|from|as|with|try|except|finally|raise|lambda|yield|global|nonlocal|pass|break|continue|None|True|False|is|assert|del|async|await|print|range|len|self)\b|\b(\d+\.?\d*)\b/g;
26	
27	function highlightPy(escaped) {
28	  return escaped.replace(PY_TOKENS, (m, com, str, kw, num) => {
29	    if (com) return `<span class="tok-com">${com}</span>`;
30	    if (str) return `<span class="tok-str">${str}</span>`;
31	    if (kw) return `<span class="tok-kw">${kw}</span>`;
32	    if (num) return `<span class="tok-num">${num}</span>`;
33	    return m;
34	  });
35	}
36	
37	// C-family keyword tint (Java / C++ / TS / Go / Kotlin / Rust / Swift). Operates on
38	// already-HTML-escaped code, so — like the Python pass — it tints keywords, // and
39	// /* */ comments, and numbers (string literals stay plain, matching highlightPy).
40	// LLD explicitly supports non-Python languages, so this stops Java rendering as a
41	// flat monochrome wall.
42	const C_TOKENS =
43	  /(\/\/[^\n]*|\/\*[\s\S]*?\*\/)|\b(abstract|class|interface|enum|extends|implements|public|private|protected|final|static|synchronized|volatile|transient|void|new|return|if|else|for|while|do|switch|case|default|break|continue|throw|throws|try|catch|finally|this|super|null|true|false|import|package|const|let|var|function|func|fun|type|struct|namespace|using|val|override|int|long|double|float|boolean|bool|char|byte|short|String|string|auto|nil)\b|\b(\d+\.?\d*[fFlLdD]?)\b/g;
44	
45	function highlightC(escaped) {
46	  return escaped.replace(C_TOKENS, (m, com, kw, num) => {
47	    if (com) return `<span class="tok-com">${com}</span>`;
48	    if (kw) return `<span class="tok-kw">${kw}</span>`;
49	    if (num) return `<span class="tok-num">${num}</span>`;
50	    return m;
51	  });
52	}
53	const C_LANGS = /^(java|c|cpp|c\+\+|cs|csharp|js|javascript|ts|typescript|go|golang|kotlin|kt|rust|rs|swift|scala)$/;
54	
55	let _mermaidSeq = 0;
56	
57	function renderCodeBlock(lang, code) {
58	  // Strip the " copy" suffix that Next.js-style docs use (```py copy) — we
59	  // handle copying ourselves; the word is meaningless as a language tag.
60	  const language = (lang || "").toLowerCase().replace(/\s+copy\s*$/, "").trim();
61	  // Mermaid -> a placeholder rendered into SVG after the text settles.
62	  if (language === "mermaid") {
63	    const raw = btoa(unescape(encodeURIComponent(code.replace(/\n$/, ""))));
64	    return `<div class="mermaid-block" data-code="${raw}" data-id="mmd-${_mermaidSeq++}"><pre class="mermaid-src">${escapeHtml(code.replace(/\n$/, ""))}</pre></div>`;
65	  }
66	  const escaped = escapeHtml(code.replace(/\n$/, ""));
67	  // Only tint blocks the model explicitly tagged python — so a bare ```...``` ASCII
68	  // trace / array diagram isn't sprayed with random keyword/number colors.
69	  const isPy = /^(py|python)$/.test(language);
70	  const body = isPy ? highlightPy(escaped) : (C_LANGS.test(language) ? highlightC(escaped) : escaped);
71	  // Suppress the language chip for plain/untagged/copy-only blocks.
72	  const label = /^(copy|text|plain|txt)$/.test(language) ? "" : language;
73	  const raw = btoa(unescape(encodeURIComponent(code.replace(/\n$/, ""))));
74	  return (
75	    `<div class="code-block"><div class="code-bar">` +
76	    `<span class="code-lang">${escapeHtml(label)}</span>` +
77	    `<button class="copy-btn" data-raw="${raw}" type="button">copy</button></div>` +
78	    `<pre><code>${body}</code></pre></div>`
79	  );
80	}
81	
82	function inlineMd(text) {
83	  // `text` is already HTML-escaped.
84	  let out = text;
85	  out = out.replace(/`([^`]+)`/g, (m, c) => `<code class="inline">${c}</code>`);
86	  // Lazy bold so inner single stars survive: **O(n*m)** -> one bold span, not garbage.
87	  out = out.replace(/\*\*([\s\S]+?)\*\*/g, "<strong>$1</strong>");
88	  // make Approach / Challenges / Trade-off labels stand out inside tiers
89	  out = out.replace(
90	    /<strong>(Approach|Challenges?|Trade-?offs?|Problem|Why it works)(:?)<\/strong>/gi,
91	    '<strong class="dd-label">$1</strong>'
92	  );
93	  // Boundary-safe *italics*: opening '*' sits at a word boundary (start, space, or '(')
94	  // and hugs its content; closing '*' is followed by space/punct/end. Keeps real emphasis
95	  // (*aggregates*, *composes*) while leaving multiplication (a*b, O(n*m), 10 * 5) untouched.
96	  out = out.replace(/(^|[\s(])\*(\S|\S[^*\n]*?\S)\*(?=[\s.,;:!?)]|$)/g, "$1<em>$2</em>");
97	  out = out.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (m, t, url) => {
98	    // `url` is already HTML-escaped here (renderMarkdown escapes before inlineMd),
99	    // so quotes are &quot; and cannot break out of the attribute. Do NOT re-escape
100	    // (that would double-escape & in query strings).
