110	function splitRow(line) {
111	  let s = line.trim();
112	  if (s.startsWith("|")) s = s.slice(1);
113	  if (s.endsWith("|")) s = s.slice(0, -1);
114	  // Honor GFM escaped pipes (\\|) so absolute-value cells like |d| or |c - n| stay in
115	  // ONE column instead of splitting the row. Protect, split, then restore the pipe.
116	  // (Sentinel + replace avoids a lookbehind regex for older-Safari compatibility.)
117	  return s
118	    .replace(/\\\|/g, "\u0001")
119	    .split("|")
120	    .map((c) => c.trim().replace(/\u0001/g, "|"));
121	}
