129	  const bodyRows = rows.slice(2);
130	  let html = '<div class="table-wrap"><table><thead><tr>';
131	  html += head.map((c) => `<th>${inlineMd(escapeHtml(c))}</th>`).join("");
132	  html += "</tr></thead><tbody>";
133	  for (const r of bodyRows) {
134	    const cells = splitRow(r);
135	    html += "<tr>" + cells.map((c) => `<td>${inlineMd(escapeHtml(c))}</td>`).join("") + "</tr>";
136	  }
137	  html += "</tbody></table></div>";
138	  return html;
139	}
