141	// Some models emit an entire Markdown table glued onto ONE line:
142	//   "| a | b | |---|---| | 1 | 2 | | 3 | 4 |"
143	// Detect that and expand it back into proper per-row lines so it renders.
144	// Conservative: only fires for >=2 columns with a clean cell grid.
145	function maybeExpandGluedTable(line) {
146	  if (!/\|\s*:?-{2,}:?\s*\|/.test(line)) return null; // needs an embedded separator run
147	  const cells = line.split("|").map((c) => c.trim());
148	  while (cells.length && cells[0] === "") cells.shift();
149	  while (cells.length && cells[cells.length - 1] === "") cells.pop();
150	  const isSep = (c) => /^:?-{2,}:?$/.test(c);
151	  const cols = cells.filter(isSep).length;
152	  if (cols < 2) return null;
153	  // Drop separator cells AND the empty cells produced by "| |" row boundaries,
154	  // then regroup the real content into rows of `cols`.
155	  const content = cells.filter((c) => c !== "" && !isSep(c));
156	  if (content.length < 2 * cols || content.length % cols !== 0) return null; // not a clean grid
157	  const out = [];
158	  for (let i = 0; i < content.length; i += cols) {
159	    out.push("| " + content.slice(i, i + cols).join(" | ") + " |");
160	  }
161	  const sep = "|" + " --- |".repeat(cols);
162	  return [out[0], sep, ...out.slice(1)]; // header, separator, data rows
163	}
