179	  if (t.startsWith("🎙")) return "script";
180	  if (t.startsWith("🤝")) return "check";
181	  if (t.startsWith("🆘")) return "sos";
182	  if (t.startsWith("🧠")) return "ask";
183	  if (t.startsWith("⚠"))  return "trap";
184	  if (t.startsWith("🗣"))  return "voice";
185	  if (t.startsWith("⚡"))  return "hard";
186	  if (t.startsWith("💥"))  return "warn";
187	  if (t.startsWith("↔"))  return "fork";
188	  if (t.startsWith("↩"))  return "prev";
189	  if (t.startsWith("🔢")) return "math";
190	  if (t.startsWith("✅")) return "ok";
191	  if (t.startsWith("🔁")) return "upgrade";
192	  if (t.startsWith("🔀")) return "tradeoff";
193	  return "";
