196	function renderMarkdown(src) {
197	  if (!src) return "";
198	  // Strip stray tool-call grammar tags the model can leak into its text stream
199	  // (e.g. a lone </parameter> just before a code fence, which lands inside a
200	  // mermaid block and breaks the diagram). These are never part of the answer.
201	  src = src.replace(
202	    /<\/?(?:parameter|antml:[a-z_]+|function_calls|invoke|function_results|tool_use|tool_result)\b[^>]*>/gi,
203	    ""
204	  );
205	  // 1) extract fenced code (and mermaid) blocks
206	  const blocks = [];
207	  const work = src.replace(/```([\w]+(?:\s+copy)?)?\s*\n?([\s\S]*?)```/g, (m, lang, code) => {
208	    blocks.push(renderCodeBlock(lang, code));
209	    return ` �BLOCK${blocks.length - 1}� `;
210	  });
211	
212	  // Pre-unwrap bold-wrapped headings (**#### Bad: ...**) BEFORE dehyphenated runs,
213	  // so the dehyphenated step doesn't split the ** from the #### and leave orphan ** paragraphs.
214	  const preUnwrapped = work.replace(/^\*\*(#{1,4}\s[\s\S]*?)\*\*\s*$/mg, "$1");
215	
216	  // split headers glued onto the end of a line (e.g. "…numbers)### Key numbers").
217	  // The preceding char must be non-space AND non-'#' so real line-start headers
218	  // (## / ### / ####) are never split.
219	  const dehyphenated = preUnwrapped.replace(/([^\s#])(#{2,4}\s)/g, "$1\n$2");
220	  const lines = [];
221	  for (const ln of dehyphenated.split("\n")) {
222	    const expanded = maybeExpandGluedTable(ln);
223	    if (expanded) lines.push(...expanded);
224	    else lines.push(ln);
225	  }
226	  let html = "";
227	  let listType = null;
228	  let para = [];
229	  let openTier = false;
230	
231	  const flushPara = () => {
232	    if (para.length) { html += `<p>${inlineMd(escapeHtml(para.join("\n")))}</p>`; para = []; }
233	  };
234	  const closeList = () => { if (listType) { html += `</${listType}>`; listType = null; } };
235	  const closeTier = () => { if (openTier) { html += "</div>"; openTier = false; } };
236	
237	  for (let i = 0; i < lines.length; i++) {
238	    let line = lines[i];
239	    // Unwrap a heading the model mistakenly bold-wrapped: **#### Bad: x** -> #### Bad: x
240	    line = line.replace(/^\*\*(#{1,4}\s[\s\S]*?)\*\*\s*$/, "$1");
241	
242	    // Strip orphan leading "** " (two stars + space) — not valid Markdown bold.
243	    // The model emits this for "spoken" text: ** "I'd start with..."
244	    line = line.replace(/^\*\*\s+/, "");
245	
246	    // Horizontal rule: --- or *** or ___ alone on a line.
247	    if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line.trim())) {
248	      flushPara(); closeList(); closeTier();
249	      html += "<hr>";
250	      continue;
251	    }
252	
253	    // Skip lone language/copy tokens the model places before a code fence
254	    // (e.g. "py" then "```python ...") — only when the next non-blank line
255	    // is a code block placeholder so we never eat real single-word paragraphs.
256	    if (/^(copy|py|js|ts|python|java|go|rust|c|cpp|cs|text|plain|txt|bash|shell|sh)$/.test(line.trim())) {
257	      let j = i + 1;
258	      while (j < lines.length && lines[j].trim() === "") j++;
259	      if (j < lines.length && /^ \x00BLOCK\d+\x00 $/.test(lines[j])) { i = j - 1; continue; }
260	    }
261	
262	    const placeholder = line.match(/^ �BLOCK(\d+)� $/);
263	    if (placeholder) { flushPara(); closeList(); html += blocks[+placeholder[1]]; continue; }
264	
265	    // GFM table: a row with pipes followed by a separator row
266	    if (line.includes("|") && i + 1 < lines.length && isTableSep(lines[i + 1])) {
267	      flushPara(); closeList();
268	      const tableLines = [line, lines[i + 1]];
269	      let j = i + 2;
270	      while (j < lines.length && lines[j].includes("|") && lines[j].trim() !== "") {
271	        tableLines.push(lines[j]); j++;
272	      }
273	      html += renderTable(tableLines);
274	      i = j - 1;
275	      continue;
276	    }
277	
278	    const h = line.match(/^(#{1,4})\s+(.*)$/);
279	    if (h) {
280	      flushPara(); closeList();
281	      const lvl = h[1].length;
282	      const tier = lvl >= 3 ? tierOf(h[2]) : null;
283	      if (tier) {
284	        // Bad/Good/Great deep-dive tier -> a colour-coded card.
285	        closeTier();
286	        const title = h[2]
287	          .replace(/^\*+\s*/, "")                                    // drop leading orphan **
288	          .replace(/^(bad|good|great)(\s+solution)?\s*[:\-—)]*\s*/i, "")
289	          .replace(/\s*\*+$/, "");                                   // drop trailing orphan **
290	        html +=
291	          `<div class="tier tier-${tier}"><div class="tier-head">` +
292	          `<span class="tier-badge">${tier}</span>` +
293	          `<span class="tier-title">${inlineMd(escapeHtml(title))}</span></div>`;
294	        openTier = true;
295	      } else {
296	        if (lvl <= 3) closeTier(); // a new section/question closes the tier card
297	        html += `<h${lvl}>${inlineMd(escapeHtml(h[2]))}</h${lvl}>`;
298	      }
299	      continue;
300	    }
301	
302	    const bq = line.match(/^>\s?(.*)$/);
303	    if (bq) {
304	      flushPara(); closeList();
305	      const bqContent = bq[1];
306	
307	      // "> | header |" followed by "> |---|" — a table embedded in a blockquote context.
308	      // Strip the leading "> " from each row and render as a normal table.
309	      if (bqContent.includes("|") && i + 1 < lines.length) {
310	        const nextBq = lines[i + 1].match(/^>\s?(.*)$/);
311	        if (nextBq && isTableSep(nextBq[1])) {
312	          const tableLines = [bqContent];
313	          let j = i + 1;
314	          while (j < lines.length) {
315	            const nb = lines[j].match(/^>\s?(.*)$/);
316	            if (nb && nb[1].trim().startsWith("|")) { tableLines.push(nb[1]); j++; }
317	            else break;
318	          }
319	          html += renderTable(tableLines);
320	          i = j - 1;
321	          continue;
322	        }
323	      }
324	
325	      // "> - item" inside a blockquote: render as a styled list item, not plain "- text".
326	      const bqLi = bqContent.match(/^[-*]\s+(.*)$/);
327	      if (bqLi) {
328	        html += `<li class="bq-li">${inlineMd(escapeHtml(bqLi[1]))}</li>`;
329	      } else {
330	        html += `<blockquote class="${markerClass(bqContent)}">${inlineMd(escapeHtml(bqContent))}</blockquote>`;
331	      }
332	      continue;
333	    }
334	
335	    // 🎙️ Script — the connected, read-aloud narration the candidate SPEAKS. The single
336	    // most important HLD element: give it a distinct teleprompter block (and feed it to
337	    // read-aloud). Detect a plain line starting with the mic emoji and absorb the spoken
338	    // paragraph (continuation lines) until a blank line / new block.
339	    if (/^\s*🎙/u.test(line)) {
340	      flushPara(); closeList(); closeTier();
341	      const head = line.replace(/^\s*🎙️?\s*(?:\*\*)?\s*(?:Script|Say[- ]?it)?\s*(?:\*\*)?\s*[:：\-—]?\s*/iu, "");
342	      const parts = [];
343	      if (head.trim()) parts.push(head.trim());
344	      let j = i + 1;
345	      while (j < lines.length) {
346	        const nx = lines[j];
347	        if (nx.trim() === "") break;
348	        if (/^\s*(#{1,4}\s|>|[-*]\s|\d+\.\s|---|🎙|💬|🤝|🆘|🧠|⚠)/u.test(nx)) break;
349	        if (/^\s*\x00?\s*BLOCK\d+/.test(nx)) break;
350	        // Strip orphan leading ** the model emits for emphasis in spoken text.
351	        parts.push(nx.trim().replace(/^\*\*\s*/, ""));
352	        j++;
353	      }
354	      i = j - 1;
355	      html +=
356	        `<aside class="script-block"><div class="script-head">🎙️ Script — say this</div>` +
357	        `<div class="script-body">${inlineMd(escapeHtml(parts.join(" ")))}</div></aside>`;
358	      continue;
359	    }
360	
361	    // Trim leading indentation first so an indented sub-bullet still renders as a
362	    // (flat) list item instead of breaking into a paragraph. Nesting is intentionally
363	    // flattened — keeping the marker readable matters more than nested <ul> depth here.
364	    const lt = line.replace(/^\s+/, "");
365	    const ul = lt.match(/^[-*]\s+(.*)$/);
366	    const ol = lt.match(/^(\d+)\.\s+(.*)$/);
367	    if (ul || ol) {
368	      flushPara();
369	      const want = ul ? "ul" : "ol";
370	      if (listType !== want) {
371	        closeList();
372	        const start = ol && +ol[1] > 1 ? ` start="${+ol[1]}"` : "";  // honor resumed numbering
373	        html += `<${want}${start}>`;
374	        listType = want;
375	      }
376	      html += `<li>${inlineMd(escapeHtml(ul ? ul[1] : ol[2]))}</li>`;
377	      continue;
378	    }
379	
380	    if (line.trim() === "") { flushPara(); closeList(); continue; }
381	    para.push(line);
382	  }
383	  flushPara(); closeList(); closeTier();
384	  return html;
385	}
