390	function ensureMermaid() {
391	  if (_mermaidPromise) return _mermaidPromise;
392	  _mermaidPromise = new Promise((resolve, reject) => {
393	    const s = document.createElement("script");
394	    s.src = "/vendor/mermaid.min.js";
395	    s.onload = () => {
396	      try {
397	        window.mermaid.initialize({
398	          startOnLoad: false,
399	          theme: "base",
400	          securityLevel: "strict",
401	          fontFamily: "ui-sans-serif, system-ui, -apple-system, Segoe UI, Roboto, sans-serif",
402	          themeVariables: {
403	            darkMode: true,
404	            background: "#0d1117",
405	            primaryColor: "#1f2937",
406	            primaryTextColor: "#e6edf3",
407	            primaryBorderColor: "#3b4757",
408	            lineColor: "#8b949e",
409	            secondaryColor: "#262d3a",
410	            tertiaryColor: "#161b22",
411	            textColor: "#e6edf3",
412	            clusterBkg: "#161b22",
413	            clusterBorder: "#30363d",
414	            edgeLabelBackground: "#0d1117",
415	            fontSize: "16px",
416	          },
417	          // useMaxWidth:false → SVG keeps its natural pixel size so the block can
418	          // scroll instead of shrinking the diagram to fit (the #1 readability bug).
419	          flowchart: { useMaxWidth: false, htmlLabels: true, nodeSpacing: 60, rankSpacing: 70, curve: "basis", padding: 12 },
420	          sequence: { useMaxWidth: false },
421	          class: { useMaxWidth: false },
422	          er: { useMaxWidth: false },
423	          state: { useMaxWidth: false },
424	        });
425	        resolve(window.mermaid);
426	      } catch (e) { reject(e); }
427	    };
428	    s.onerror = () => reject(new Error("failed to load mermaid"));
429	    document.head.appendChild(s);
430	  });
431	  return _mermaidPromise;
432	}
