434	// After a diagram renders, let it keep its natural pixel width (so its block can
435	// scroll horizontally instead of squeezing the SVG down) and mark it done.
436	function _onMermaidRendered(el) {
437	  el.classList.add("rendered");
438	  const svg = el.querySelector("svg");
439	  if (svg) {
440	    svg.style.maxWidth = "none";
441	    svg.removeAttribute("width"); // keep viewBox + height so it scales cleanly
442	    // If the diagram is wider than its container, left-anchor it (so the part you
443	    // read first is visible) rather than centering it half-off-screen.
444	    requestAnimationFrame(() => {
445	      if (el.scrollWidth > el.clientWidth + 4) el.classList.add("mmd-wide");
446	    });
447	  }
448	}
