450	// Tap/click a rendered diagram to open it full-screen (readable + scrollable) on
451	// laptop and iPhone. One delegated listener, no library needed.
452	let _mermaidZoomWired = false;
453	function wireMermaidZoom() {
454	  if (_mermaidZoomWired) return;
455	  _mermaidZoomWired = true;
456	  document.addEventListener("click", (e) => {
457	    const block = e.target.closest(".mermaid-block.rendered:not(.mermaid-error)");
458	    if (!block) return;
459	    const svg = block.querySelector("svg");
460	    if (!svg) return;
461	    const overlay = document.createElement("div");
462	    overlay.className = "mermaid-zoom";
463	    const clone = svg.cloneNode(true);
464	    // cloneNode(true) copies inline styles set by _onMermaidRendered (maxWidth:"none").
465	    // Clear that so CSS max-width:calc(100vw - 48px) can scale the SVG to fit the viewport.
466	    clone.removeAttribute("width");
467	    clone.style.maxWidth = "";
468	    // Always start the zoom view from the left edge (the start of the diagram),
469	    // not the center — wide diagrams were opening with the beginning off-screen.
470	    clone.style.alignSelf = "flex-start";
471	    overlay.appendChild(clone);
472	    const hint = document.createElement("div");
473	    hint.className = "mermaid-zoom-hint";
474	    hint.textContent = "drag to pan · tap to close · Esc to close";
475	    overlay.appendChild(hint);
476	
477	    const close = () => { overlay.remove(); document.removeEventListener("keydown", onKey); };
478	    const onKey = (ev) => { if (ev.key === "Escape") close(); };
479	    document.addEventListener("keydown", onKey);
480	
481	    // Drag-to-pan: track mouse movement; only fire close() on a genuine tap (< 6px travel).
482	    let dragStartX = 0, dragStartY = 0, scrollStartX = 0, scrollStartY = 0, didDrag = false;
483	    overlay.addEventListener("mousedown", (ev) => {
484	      dragStartX = ev.clientX; dragStartY = ev.clientY;
485	      scrollStartX = overlay.scrollLeft; scrollStartY = overlay.scrollTop;
486	      didDrag = false;
487	      overlay.classList.add("is-dragging");
488	      ev.preventDefault();
489	    });
490	    overlay.addEventListener("mousemove", (ev) => {
491	      if (!overlay.classList.contains("is-dragging")) return;
492	      const dx = ev.clientX - dragStartX;
493	      const dy = ev.clientY - dragStartY;
494	      if (Math.abs(dx) > 4 || Math.abs(dy) > 4) didDrag = true;
495	      overlay.scrollLeft = scrollStartX - dx;
496	      overlay.scrollTop  = scrollStartY - dy;
497	    });
498	    overlay.addEventListener("mouseup", () => {
499	      overlay.classList.remove("is-dragging");
500	      if (!didDrag) close();
501	    });
502	    overlay.addEventListener("mouseleave", () => overlay.classList.remove("is-dragging"));
503	
504	    document.body.appendChild(overlay);
505	  });
506	}
