508	// Render any not-yet-rendered mermaid blocks inside `root`.
509	async function renderMermaidIn(root) {
510	  if (!root) return;
511	  wireMermaidZoom();
512	  const pending = root.querySelectorAll(".mermaid-block:not([data-done])");
513	  if (!pending.length) return;
514	  let mermaid;
515	  try { mermaid = await ensureMermaid(); }
516	  catch { return; } // leave the source <pre> as a readable fallback
517	  for (const el of pending) {
518	    el.setAttribute("data-done", "1");
519	    let code = "";
520	    try { code = decodeURIComponent(escape(atob(el.dataset.code))).trim(); } catch { continue; }
521	    try {
522	      const { svg } = await mermaid.render(el.dataset.id, code);
523	      el.innerHTML = svg;
524	      _onMermaidRendered(el);
525	    } catch (err) {
526	      // Salvage the common failure: breaking chars (| : ( ) < > /) inside quoted
527	      // labels (e.g. erDiagram `status "active|completed"`). Retry once cleaned.
528	      try {
529	        const safe = code.replace(/"([^"]*)"/g, (m, s) => '"' + s.replace(/[|:()<>/\[\]]/g, " ") + '"');
530	        const { svg } = await mermaid.render(el.dataset.id + "-s", safe);
531	        el.innerHTML = svg;
532	        _onMermaidRendered(el);
533	      } catch (e2) {
534	        el.classList.add("mermaid-error"); // keep the source visible as fallback
535	      }
536	    }
537	  }
538	}
